use std::collections::HashMap;
use std::thread;
use std::time::Duration;

struct MetricResult {
    name: String,
    data: HashMap<String, f64>,
}

fn fetch_metric(api_name: &str) -> Result<MetricResult, String> {
    println!("Starting data retrieval for {}", api_name);
    thread::sleep(Duration::from_millis(500));
    let mut data = HashMap::new();
    data.insert("cpu_usage".to_string(), (api_name.len() as f64) * 1.2);
    data.insert("memory_free".to_string(), 8192.0 - (api_name.chars().count() as f64) * 100.0);
    Ok(MetricResult {
        name: api_name.to_string(),
        data,
    })
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let metrics_to_poll = vec!["cpu_monitor".to_string(), "mem_monitor".to_string(), "disk_io".to_string()];
    let mut handles = vec![];

    for metric in metrics_to_poll.iter().take(3) {
        let api_name = metric.clone();
        let handle = thread::spawn(move || -> Result<MetricResult, String> {
            fetch_metric(&api_name)
        });
        handles.push(handle);
    }

    let mut final_results: Vec<MetricResult> = vec![];
    for handle in handles {
        match handle.join().expect("Thread panicked") {
            Ok(result) => final_results.push(result),
            Err(e) => eprintln!("Failed to gather data: {}", e),
        }
    }

    println!("n--- Batch Processing Complete ---nTotal metrics gathered: {}", final_results.len());
    for result in final_results {
        println!("Metric: {}", result.name);
        for (key, value) in result.data {
            println!("  - {}: {:.2}", key, value);
        }
    }

    Ok(())
}

use std::collections::HashMap;

struct MatrixProcessor {
    data: Vec<f64>,
    rows: usize,
    cols: usize,
}

impl MatrixProcessor {
    fn new(data: Vec<f64>, rows: usize, cols: usize) -> Self {
        MatrixProcessor { data, rows, cols }
    }

    fn apply_lazy_transform<F>(self, transform_fn: F) -> Box<dyn Fn() -> f64>
    where
        F: Fn(usize, usize, f64) -> f64 + 'static,
    {
        let data = self.data;
        let rows = self.rows;
        let cols = self.cols;

        Box::new(move || {
            for i in 0..rows {
                for j in 0..cols {
                    let index = i * cols + j;
                    return (transform_fn)(i, j, data[index]);
                }
            }
            0.0
        })
    }
}

fn main() {
    let raw_data: Vec<f64> = vec![1.0, 2.0, 3.0, 4.0];
    let rows = 2;
    let cols = 2;

    let processor = MatrixProcessor::new(raw_data, rows, cols);

    let lazy_op: Box<dyn Fn() -> f64> = processor.apply_lazy_transform(|i, j, val| {
        (val * (i as f64) * (j as f64)).sin()
    });

    let result = lazy_op();
    println!("Final computed value: {}", result);
}

use std::collections::HashMap;

struct DataFrame {
    data: HashMap<String, Vec<f64>>,
}

impl DataFrame {
    fn new() -> Self {
        DataFrame { data: HashMap::new() }
    }

    fn add_column(&mut self, name: &str, values: Vec<f64>) {
        self.data.insert(name.to_string(), values);
    }

    fn filter_by_threshold(data_map: HashMap<String, Vec<f64>>, threshold: f64) -> Result<HashMap<String, Vec<f64>>, String> {
        let mut filtered_data = HashMap::new();
        for (column_name, values) in data_map.iter() {
            let new_values: Vec<f64> = values.iter().filter(|&&val| val >= threshold).cloned().collect();
            if !new_values.is_empty() {
                filtered_data.insert(column_name.clone(), new_values);
            }
        }
        Ok(filtered_data)
    }
}

fn main() -> Result<(), String> {
    let mut df = DataFrame::new();
    df.add_column("Age", vec![22.0, 35.0, 19.0, 48.0]);
    df.add_column("Score", vec![88.0, 72.0, 95.0, 60.0]);

    let data_map: HashMap<String, Vec<f64>> = df.data;
    let threshold_age: f64 = 30.0;

    match DataFrame::filter_by_threshold(data_map, threshold_age) {
        Ok(filtered) => {
            println!("Filtering complete for threshold: {}", threshold_age);
            for (name, values) in filtered { 
                println!("{}: {:?}", name, values);
            }
        },
        Err(e) => {
            println!("Error during filtering: {}", e);
        }
    }

    Ok(())
}

use std::collections::VecDeque;

struct SensorReading {
    timesestamp: u64,
    value: f32,
}

fn process_data_stream(readings: VecDeque<SensorReading>) -> Vec<f32> {
    let mut processed_values = Vec::new();
    for reading in readings.into_iter() {
        if reading.value > 0.0 {
            processed_values.push(reading.value * 1.5);
        }
    }
    processed_values
}

fn main() {
    let mut buffer: VecDeque<SensorReading> = VecDeque::new();
    buffer.push_back(SensorReading { timesestamp: 1678886400, value: 5.0 });
    buffer.push_back(SensorReading { timesestamp: 1678886410, value: -2.3 });
    buffer.push_back(SensorReading { timesestamp: 1678886420, value: 10.0 });

    let results = process_data_stream(buffer);

    for result in results {
        println!("Processed Value: {}", result);
    }
}

use std::collections::HashMap;

struct ConfigProcessor {
    secret_key: String,
}
impl ConfigProcessor {
    fn new(key: &str) -> Self {
        ConfigProcessor { secret_key: key.to_string() }
    }

    fn process_settings(&self, raw_data: HashMap<String, String>) -> Vec<String> {
        let mut processed_items = Vec::new();
        for (setting_name, value) in raw_data {
            let result = self.create_processor_closure(value); 
            processed_items.push(result);
        }
        processed_items
    }

    fn create_processor_closure(&self, initial_value: String) -> String {
        let key_ref = &self.secret_key;
        let closure = move |data: String| -> String {
            format!("Processed({}) with key {} and prepended value {}", data, key_ref, initial_value)
        };
        closure(String::from("dummy"))
    }
}
